#include<bits/stdc++.h>
using namespace std;
string s;
int main(){
    cin>>s;
    if(s[0]-'0'>5){
        if(s.size()==1)cout<<s[0]-'0';
        else for(int i=0;i<=s.size();i++)cout<<((i==0||i==s.size()-1)?1:0);
    }
    else if(s.size()>4||(s.size()==4&&s[0]-'0'>=8)){
        int is=(((8-s[0]+'0')<=s[1]-'0')?1:0);
        cout<<s[0]-'0'+is<<8-s[0]+'0'-is;
        for(int i=2;i<s.size();i++)cout<<0;
    }
    else{
        int n=0,ans=-1;
        for(int i=0;i<s.size();i++)n=n*10+s[i]-'0';
        for(int i=n;i<2*n;i++){
            int cnt1=0,cnt2=0;
            int tmp1=i,tmp2=i+1;
            while(tmp1)cnt1+=tmp1%10,tmp1/=10;
            while(tmp2)cnt2+=tmp2%10,tmp2/=10;
            if(i%cnt1==0&&(i+1)%cnt2==0){ans=i;break;}
        }
        cout<<ans<<"\n";
    }
    return 0;
}
